116	// ── rule → attribution 字段映射 ───────────────────────────────────────────────
117	// 从 rule 的 attribution 字段推导出 ProxySegmentAttribution 的各语义字段。
118	// 这里是唯一的"rule → 字段"映射点，attribution 主流程不再重复这些逻辑。
119	
120	interface RuleMatchResult {
121	  category: SegmentCategory;
122	  mechanism: ProxySegmentAttribution["mechanism"];
123	  confidence: ProxySegmentAttribution["confidence"];
124	  attributedSource: MutationSourceKind;
125	  lifecycle: SegmentLifecycle | undefined;
126	  ruleId: string;
127	  flags: SegmentFlag[];
128	  notes: string[] | undefined;
129	}
130	
131	function applyRuleMatch(
132	  rule: ContextLedgerRule,
133	  groups: Record<string, string | undefined> | null,
134	): RuleMatchResult {
135	  const attr = rule.attribution!;
136	
137	  // lifecycle：从 rule.reconstruction.emits.lifecycle 推导
138	  const lifecycle = rule.reconstruction?.emits?.lifecycle;
139	
140	  // flags
141	  const flags: SegmentFlag[] = [];
142	  if (rule.reconstruction?.emits?.flags?.includes("injected")) flags.push("injected");
143	  if (rule.reconstruction?.emits?.flags?.includes("known_noise")) flags.push("known_noise");
144	
145	  // category：从 rule.attribution.category
146	  const category = attr.category;
147	
148	  // mechanism：从 rule.attribution.mechanism
149	  const mechanism = attr.mechanism;
150	
151	  // confidence：有命名捕获组且全部非空 → exact；否则按 rule.reconciliation.confidence 降级
152	  const hasGroups = groups && Object.keys(groups).length > 0;
153	  const allGroupsFilled = hasGroups && Object.values(groups!).every((v) => v !== undefined && v !== "");
154	  const baseConfidence = rule.reconciliation?.confidence ?? "inferred";
155	  const confidence: ProxySegmentAttribution["confidence"] =
156	    attr.matchMode === "exact" ? "exact"
157	    : allGroupsFilled ? "exact"
158	    : hasGroups ? "inferred"
159	    : baseConfidence;
160	
161	  // attributedSource：tool_use/tool_result 由 wire schema 决定，其余由 rule 决定
162	  const attributedSource: MutationSourceKind =
163	    category === "tool_use" || category === "tool_result" ? "jsonl" : "harness_rule";
164	
165	  // notes：billing rule 专用捕获组、dynamic section 专用捕获组
166	  let notes: string[] | undefined;
167	  if (category === "billing_noise" && groups) {
168	    notes = [
169	      `cc_version=${groups["version"] ?? "?"}`,
170	      `cc_entrypoint=${groups["entrypoint"] ?? "?"}`,
171	      ...(groups["cch"] ? [`cch=${groups["cch"]}`] : []),
172	      ...(groups["workload"] ? [`cc_workload=${groups["workload"]}`] : []),
173	    ].filter((n) => !n.endsWith("?"));
174	    if (notes.length === 0) notes = undefined;
175	  } else if (rule.ruleId === CLAUDE_CODE_ENVIRONMENT_SECTION_RULE.ruleId && groups) {
176	    notes = [
177	      `cwd=${groups["cwd"] ?? "?"}`,
178	      `platform=${groups["platform"] ?? "?"}`,
179	      `shell=${groups["shell"] ?? "?"}`,
180	      `osVersion=${groups["osVersion"] ?? "?"}`,
181	      `model=${groups["modelDesc"] ?? "?"}`,
182	      ...(groups["cutoff"] ? [`cutoff=${groups["cutoff"]}`] : []),
183	    ];
184	  } else if (rule.ruleId === CLAUDE_CODE_AUTO_MEMORY_SECTION_RULE.ruleId && groups?.["memoryDir"]) {
185	    notes = [`memoryDir=${groups["memoryDir"]}`];
186	  } else if (rule.ruleId === CLAUDE_CODE_CONTEXT_MANAGEMENT_RULE.ruleId && groups) {
187	    if (groups["currentBranch"]) {
188	      notes = [
189	        `currentBranch=${groups["currentBranch"]}`,
190	        `mainBranch=${groups["mainBranch"] ?? "?"}`,
191	        ...(groups["gitUser"] ? [`gitUser=${groups["gitUser"]}`] : []),
192	      ];
193	    } else {
194	      notes = ["no_git_repo: gitStatus block absent"];
195	    }
196	  }
197	
198	  // Session-specific guidance：embedded variant 升 confidence
199	  if (rule.ruleId === CLAUDE_CODE_SESSION_GUIDANCE_EMBEDDED_RULE.ruleId) {
200	    return { category, mechanism, confidence: "exact", attributedSource, lifecycle, ruleId: rule.ruleId, flags, notes };
201	  }
202	
203	  return { category, mechanism, confidence, attributedSource, lifecycle, ruleId: rule.ruleId, flags, notes };
204	}
