223	function parseMsgIndex(jsonPath: string | undefined): number | null {
224	  if (!jsonPath) return null;
225	  const m = /reqBody\.messages\[(\d+)\]/.exec(jsonPath);
226	  return m ? parseInt(m[1]!, 10) : null;
